  render: args => {
    const [latestEvent, setLatestEvent] = React.useState<[AnalyticsEventName, AnalyticsEventData]>();
    return <AnalyticsListener onEvent={(name, data) => setLatestEvent([name, data])}>
                <Stack gap={1}>
                    {latestEvent === undefined ? null : <>
                            <Text as="p">Latest event data: {latestEvent?.[0]}</Text>
                            <pre>{JSON.stringify(latestEvent?.[1])}</pre>
                        </>}
                    <AnalyticsContext data={{
          userID: 'User-ABC'
        }}>
                        <Box border padding={1}>
                            <Text as="p">Outer context: userID</Text>
                            <Trigger eventName="first button" />

                            <AnalyticsContext data={{
              businessID: 'Org-123'
            }}>
                                <Box border padding={1}>
                                    <Text as="p">Middle context: businessID</Text>
                                    <Trigger eventName="second button" />

                                    <AnalyticsContext data={{
                  pageID: 'Page-ZZZ'
                }}>
                                        <Box border padding={1}>
                                            <Text as="p">Inner context: pageID</Text>
                                            <Trigger eventName="third button" />
                                        </Box>
                                    </AnalyticsContext>
                                </Box>
                            </AnalyticsContext>
                        </Box>
                    </AnalyticsContext>
                </Stack>
            </AnalyticsListener>;
  }
